import{_ as a,c as i,o as s,a1 as o}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Advertencia de TdS: Riesgos de Cuenta y Prácticas de Seguridad | Antigravity Auth","description":"Aprende sobre los riesgos de uso y las prácticas de seguridad de cuentas del plugin Antigravity Auth. Comprende escenarios de alto riesgo, mecanismos de shadow ban y la diferencia entre rate limits. Domina estrategias de múltiples cuentas, control de uso y métodos de calentamiento de cuentas.","frontmatter":{"title":"Advertencia de TdS: Riesgos de Cuenta y Prácticas de Seguridad | Antigravity Auth","sidebarTitle":"Evita que bloqueen tu cuenta","subtitle":"Advertencia de TdS: Riesgos de Cuenta y Prácticas de Seguridad","description":"Aprende sobre los riesgos de uso y las prácticas de seguridad de cuentas del plugin Antigravity Auth. Comprende escenarios de alto riesgo, mecanismos de shadow ban y la diferencia entre rate limits. Domina estrategias de múltiples cuentas, control de uso y métodos de calentamiento de cuentas.","tags":["FAQ","Advertencia de riesgos","Seguridad de cuentas"],"prerequisite":["start-quick-install"],"order":5},"headers":[],"relativePath":"es/NoeFabris/opencode-antigravity-auth/faq/tos-warning/index.md","filePath":"es/NoeFabris/opencode-antigravity-auth/faq/tos-warning/index.md"}'),t={name:"es/NoeFabris/opencode-antigravity-auth/faq/tos-warning/index.md"};function n(r,e,l,d,c,u){return s(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="advertencia-de-tds" tabindex="-1">Advertencia de TdS <a class="header-anchor" href="#advertencia-de-tds" aria-label="Permalink to &quot;Advertencia de TdS&quot;">​</a></h1><p>Al completar esta lección, comprenderás los riesgos potenciales de usar el plugin Antigravity Auth y cómo proteger la seguridad de tu cuenta de Google.</p><h2 id="tu-situacion-actual" tabindex="-1">Tu Situación Actual <a class="header-anchor" href="#tu-situacion-actual" aria-label="Permalink to &quot;Tu Situación Actual&quot;">​</a></h2><p>Estás considerando usar el plugin Antigravity Auth para acceder a los modelos de IA de Google Antigravity, pero tienes algunas preocupaciones:</p><ul><li>Has visto informes en la comunidad sobre cuentas bloqueadas o con shadow ban</li><li>Te preocupa que usar herramientas no oficiales viole los términos de servicio de Google</li><li>No estás seguro de si usar una cuenta nueva o una existente</li><li>Quieres saber cómo reducir los riesgos</li></ul><p>Estas preocupaciones son válidas. Usar cualquier herramienta no oficial conlleva ciertos riesgos. Este artículo te ayudará a comprender los riesgos específicos y las estrategias de respuesta.</p><h2 id="cuando-necesitas-leer-esta-leccion" tabindex="-1">Cuándo Necesitas Leer Esta Lección <a class="header-anchor" href="#cuando-necesitas-leer-esta-leccion" aria-label="Permalink to &quot;Cuándo Necesitas Leer Esta Lección&quot;">​</a></h2><ul><li><strong>Antes de instalar el plugin</strong>: Comprende los riesgos antes de decidir si usarlo</li><li><strong>Al elegir una cuenta</strong>: Decide qué cuenta de Google usar para la autenticación</li><li><strong>Cuando encuentres bloqueos</strong>: Comprende las posibles causas y medidas preventivas</li><li><strong>Al registrar nuevos usuarios</strong>: Evita patrones de operación de alto riesgo</li></ul><hr><h2 id="resumen-de-riesgos-principales" tabindex="-1">Resumen de Riesgos Principales <a class="header-anchor" href="#resumen-de-riesgos-principales" aria-label="Permalink to &quot;Resumen de Riesgos Principales&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">Advertencia Importante</p><p><strong>El uso de este plugin puede violar los Términos de Servicio de Google.</strong></p><p>Algunos usuarios han reportado que sus cuentas de Google fueron bloqueadas o recibieron shadow ban (restricción de acceso sin notificación explícita).</p><p><strong>Al usar este plugin, aceptas la siguiente declaración:</strong></p><ol><li>Esta es una herramienta no oficial, no aprobada ni respaldada por Google</li><li>Tu cuenta de Google puede ser suspendida o bloqueada permanentemente</li><li>Asumes todos los riesgos y consecuencias de usar este plugin</li></ol></div><h3 id="¿que-es-el-shadow-ban" tabindex="-1">¿Qué es el Shadow Ban? <a class="header-anchor" href="#¿que-es-el-shadow-ban" aria-label="Permalink to &quot;¿Qué es el Shadow Ban?&quot;">​</a></h3><p><strong>Shadow Ban</strong> es una medida restrictiva que Google aplica a cuentas sospechosas. A diferencia del bloqueo directo, el shadow ban no muestra mensajes de error explícitos, sino que:</p><ul><li>Las solicitudes API devuelven errores 403 o 429</li><li>La cuota muestra disponibilidad, pero en realidad no se puede llamar</li><li>Otras cuentas funcionan normalmente, solo la cuenta marcada se ve afectada</li></ul><p>El shadow ban generalmente dura varios días o semanas y no se puede recuperar mediante apelación.</p><hr><h2 id="escenarios-de-alto-riesgo" tabindex="-1">Escenarios de Alto Riesgo <a class="header-anchor" href="#escenarios-de-alto-riesgo" aria-label="Permalink to &quot;Escenarios de Alto Riesgo&quot;">​</a></h2><p>Los siguientes escenarios aumentan significativamente el riesgo de que tu cuenta sea marcada o bloqueada:</p><h3 id="🚨-escenario-1-cuentas-de-google-completamente-nuevas" tabindex="-1">🚨 Escenario 1: Cuentas de Google Completamente Nuevas <a class="header-anchor" href="#🚨-escenario-1-cuentas-de-google-completamente-nuevas" aria-label="Permalink to &quot;🚨 Escenario 1: Cuentas de Google Completamente Nuevas&quot;">​</a></h3><p><strong>Nivel de riesgo: Extremadamente alto</strong></p><p>Las cuentas de Google recién registradas que usan este plugin tienen una probabilidad muy alta de ser bloqueadas. Razones:</p><ul><li>Las nuevas cuentas carecen de datos históricos de comportamiento, lo que las hace susceptibles de ser marcadas por los sistemas de detección de abuso de Google</li><li>Un gran número de llamadas API se considera comportamiento anormal en cuentas nuevas</li><li>Google aplica una revisión más estricta a las cuentas nuevas</li></ul><p><strong>Recomendación</strong>: No crees cuentas nuevas específicamente para este plugin.</p><h3 id="🚨-escenario-2-cuenta-nueva-suscripcion-pro-ultra" tabindex="-1">🚨 Escenario 2: Cuenta Nueva + Suscripción Pro/Ultra <a class="header-anchor" href="#🚨-escenario-2-cuenta-nueva-suscripcion-pro-ultra" aria-label="Permalink to &quot;🚨 Escenario 2: Cuenta Nueva + Suscripción Pro/Ultra&quot;">​</a></h3><p><strong>Nivel de riesgo: Extremadamente alto</strong></p><p>Las cuentas recién registradas que inmediatamente se suscriben a los servicios Pro o Ultra de Google frecuentemente son marcadas y bloqueadas. Razones:</p><ul><li>Los patrones de uso intensivo después de la suscripción en cuentas nuevas parecen abuso</li><li>Google aplica una revisión más estricta a los nuevos usuarios de pago</li><li>Este patrón difiere demasiado de la trayectoria de crecimiento de los usuarios normales</li></ul><p><strong>Recomendación</strong>: Permite que la cuenta &quot;crezca naturalmente&quot; durante un tiempo (al menos varios meses) antes de considerar una suscripción.</p><h3 id="🟡-escenario-3-gran-cantidad-de-solicitudes-en-corto-tiempo" tabindex="-1">🟡 Escenario 3: Gran Cantidad de Solicitudes en Corto Tiempo <a class="header-anchor" href="#🟡-escenario-3-gran-cantidad-de-solicitudes-en-corto-tiempo" aria-label="Permalink to &quot;🟡 Escenario 3: Gran Cantidad de Solicitudes en Corto Tiempo&quot;">​</a></h3><p><strong>Nivel de riesgo: Alto</strong></p><p>Iniciar un gran número de solicitudes API en un período corto, o usar frecuentemente proxies paralelos/sesiones múltiples, activará límites de velocidad y detección de abuso. Razones:</p><ul><li>Los patrones de solicitud de OpenCode son más intensivos que las aplicaciones nativas (llamadas de herramientas, reintentos, transmisión, etc.)</li><li>Las solicitudes de alta concurrencia activan los mecanismos de protección de Google</li></ul><p><strong>Recomendación</strong>:</p><ul><li>Controla la frecuencia de solicitudes y el número de concurrentes</li><li>Evita iniciar múltiples agentes paralelos simultáneamente</li><li>Usa rotación de cuentas múltiples para dispersar solicitudes</li></ul><h3 id="🟡-escenario-4-usar-la-unica-cuenta-de-google" tabindex="-1">🟡 Escenario 4: Usar la Única Cuenta de Google <a class="header-anchor" href="#🟡-escenario-4-usar-la-unica-cuenta-de-google" aria-label="Permalink to &quot;🟡 Escenario 4: Usar la Única Cuenta de Google&quot;">​</a></h3><p><strong>Nivel de riesgo: Medio</strong></p><p>Si solo tienes una cuenta de Google y dependes de ella para acceder a servicios críticos (Gmail, Drive, etc.), el riesgo es mayor. Razones:</p><ul><li>El bloqueo de la cuenta afectará tu trabajo diario</li><li>No se puede recuperar mediante apelación</li><li>Falta de plan de respaldo</li></ul><p><strong>Recomendación</strong>: Usa una cuenta independiente que no dependa de servicios críticos.</p><hr><h2 id="mejores-practicas-recomendadas" tabindex="-1">Mejores Prácticas Recomendadas <a class="header-anchor" href="#mejores-practicas-recomendadas" aria-label="Permalink to &quot;Mejores Prácticas Recomendadas&quot;">​</a></h2><h3 id="✅-practicas-recomendadas" tabindex="-1">✅ Prácticas Recomendadas <a class="header-anchor" href="#✅-practicas-recomendadas" aria-label="Permalink to &quot;✅ Prácticas Recomendadas&quot;">​</a></h3><p><strong>1. Usa una Cuenta de Google Establecida</strong></p><p>Prioriza cuentas de Google que hayan estado en uso durante algún tiempo (se recomienda 6 meses o más):</p><ul><li>Tienen historial de uso normal de servicios de Google (Gmail, Drive, Google Search, etc.)</li><li>Sin historial de violaciones</li><li>La cuenta está vinculada a un número de teléfono y ha completado la verificación</li></ul><p><strong>2. Configura Múltiples Cuentas</strong></p><p>Agrega varias cuentas de Google para dispersar solicitudes mediante rotación:</p><ul><li>Configura al menos 2-3 cuentas</li><li>Usa la estrategia <code>account_selection_strategy: &quot;hybrid&quot;</code> (predeterminada)</li><li>Cambia automáticamente de cuenta cuando se encuentren límites de velocidad</li></ul><p><strong>3. Controla el Uso</strong></p><ul><li>Evita solicitudes intensivas en cortos períodos de tiempo</li><li>Reduce el número de agentes paralelos</li><li>Establece <code>max_rate_limit_wait_seconds: 0</code> en <code>antigravity.json</code> para fallar rápidamente en lugar de reintentar</li></ul><p><strong>4. Monitorea el Estado de las Cuentas</strong></p><p>Verifica regularmente el estado de las cuentas:</p><ul><li>Revisa <code>rateLimitResetTimes</code> en <code>~/.config/opencode/antigravity-accounts.json</code></li><li>Habilita logs de depuración: <code>OPENCODE_ANTIGRAVITY_DEBUG=1 opencode</code></li><li>Pausa el uso durante 24-48 horas cuando encuentres errores 403/429</li></ul><p><strong>5. &quot;Calienta&quot; Primero en la Interfaz Oficial</strong></p><p>Método reportado como efectivo por usuarios de la comunidad:</p><ol><li>Inicia sesión en <a href="https://idx.google.com/" target="_blank" rel="noreferrer">Antigravity IDE</a> en tu navegador</li><li>Ejecuta algunos prompts simples (como &quot;hola&quot;, &quot;¿cuánto es 2+2?&quot;)</li><li>Después de 5-10 llamadas exitosas, comienza a usar el plugin</li></ol><p><strong>Principio</strong>: Usar la cuenta a través de la interfaz oficial hace que Google considere que se trata de comportamiento de usuario normal, reduciendo el riesgo de ser marcado.</p><h3 id="❌-practicas-a-evitar" tabindex="-1">❌ Prácticas a Evitar <a class="header-anchor" href="#❌-practicas-a-evitar" aria-label="Permalink to &quot;❌ Prácticas a Evitar&quot;">​</a></h3><ul><li>❌ Crear cuentas de Google completamente nuevas específicamente para este plugin</li><li>❌ Suscribirte inmediatamente a Pro/Ultra en una cuenta recién registrada</li><li>❌ Usar tu única cuenta de servicios críticos (como correo de trabajo)</li><li>❌ Reintentar repetidamente después de activar el límite 429</li><li>❌ Iniciar una gran cantidad de agentes paralelos simultáneamente</li><li>❌ Enviar <code>antigravity-accounts.json</code> al control de versiones</li></ul><hr><h2 id="preguntas-frecuentes" tabindex="-1">Preguntas Frecuentes <a class="header-anchor" href="#preguntas-frecuentes" aria-label="Permalink to &quot;Preguntas Frecuentes&quot;">​</a></h2><h3 id="p-mi-cuenta-fue-bloqueada-¿puedo-apelar" tabindex="-1">P: Mi cuenta fue bloqueada, ¿puedo apelar? <a class="header-anchor" href="#p-mi-cuenta-fue-bloqueada-¿puedo-apelar" aria-label="Permalink to &quot;P: Mi cuenta fue bloqueada, ¿puedo apelar?&quot;">​</a></h3><p><strong>R: No.</strong></p><p>Si el bloqueo o shadow ban fue activado por la detección de abuso de Google a través de este plugin, generalmente no se puede recuperar mediante apelación. Razones:</p><ul><li>El bloqueo se activa automáticamente basado en patrones de uso de la API</li><li>Google mantiene una actitud estricta hacia el uso de herramientas no oficiales</li><li>Al apelar, necesitas explicar el propósito de la herramienta, pero este plugin en sí puede ser considerado una violación</li></ul><p><strong>Recomendación</strong>:</p><ul><li>Usa otras cuentas no afectadas</li><li>Si todas las cuentas están bloqueadas, usa directamente <a href="https://idx.google.com/" target="_blank" rel="noreferrer">Antigravity IDE</a></li><li>Evita continuar intentando en cuentas bloqueadas</li></ul><h3 id="p-¿el-uso-de-este-plugin-definitivamente-resultara-en-un-bloqueo" tabindex="-1">P: ¿El uso de este plugin definitivamente resultará en un bloqueo? <a class="header-anchor" href="#p-¿el-uso-de-este-plugin-definitivamente-resultara-en-un-bloqueo" aria-label="Permalink to &quot;P: ¿El uso de este plugin definitivamente resultará en un bloqueo?&quot;">​</a></h3><p><strong>R: No necesariamente.</strong></p><p>La mayoría de los usuarios no han encontrado problemas al usar este plugin. El riesgo depende de:</p><ul><li>Edad de la cuenta e historial de comportamiento</li><li>Frecuencia de uso y patrones de solicitud</li><li>Si se siguen las mejores prácticas</li></ul><p><strong>Evaluación de riesgo</strong>:</p><ul><li>Cuenta antigua + uso moderado + rotación de cuentas → Bajo riesgo</li><li>Cuenta nueva + solicitudes intensivas + cuenta única → Alto riesgo</li></ul><h3 id="p-¿cual-es-la-diferencia-entre-shadow-ban-y-rate-limit" tabindex="-1">P: ¿Cuál es la diferencia entre shadow ban y rate limit? <a class="header-anchor" href="#p-¿cual-es-la-diferencia-entre-shadow-ban-y-rate-limit" aria-label="Permalink to &quot;P: ¿Cuál es la diferencia entre shadow ban y rate limit?&quot;">​</a></h3><p><strong>R: Fundamentalmente diferentes, formas de recuperación también diferentes.</strong></p><table tabindex="0"><thead><tr><th>Característica</th><th>Shadow Ban</th><th>Rate Limit (429)</th></tr></thead><tbody><tr><td>Causa de activación</td><td>Detección de abuso, marcado como sospechoso</td><td>Frecuencia de solicitud excede la cuota</td></tr><tr><td>Código de error</td><td>403 o falla silenciosa</td><td>429 Too Many Requests</td></tr><tr><td>Duración</td><td>Días a semanas</td><td>Horas a un día</td></tr><tr><td>Método de recuperación</td><td>No se puede recuperar, necesitas otra cuenta</td><td>Esperar reinicio o cambiar de cuenta</td></tr><tr><td>¿Prevenible?</td><td>Reducir riesgo siguiendo mejores prácticas</td><td>Controlar frecuencia de solicitudes</td></tr></tbody></table><h3 id="p-¿se-pueden-usar-cuentas-de-google-empresariales" tabindex="-1">P: ¿Se pueden usar cuentas de Google empresariales? <a class="header-anchor" href="#p-¿se-pueden-usar-cuentas-de-google-empresariales" aria-label="Permalink to &quot;P: ¿Se pueden usar cuentas de Google empresariales?&quot;">​</a></h3><p><strong>R: No se recomienda.</strong></p><p>Las cuentas empresariales generalmente están vinculadas a servicios y datos críticos, y el impacto del bloqueo es más severo. Además:</p><ul><li>Las cuentas empresariales tienen revisiones más estrictas</li><li>Puede violar las políticas de TI de la empresa</li><li>El riesgo es asumido por el individuo, pero afecta al equipo</li></ul><p><strong>Recomendación</strong>: Usa cuentas personales.</p><h3 id="p-¿las-cuentas-multiples-pueden-evitar-completamente-el-bloqueo" tabindex="-1">P: ¿Las cuentas múltiples pueden evitar completamente el bloqueo? <a class="header-anchor" href="#p-¿las-cuentas-multiples-pueden-evitar-completamente-el-bloqueo" aria-label="Permalink to &quot;P: ¿Las cuentas múltiples pueden evitar completamente el bloqueo?&quot;">​</a></h3><p><strong>R: No pueden evitarlo completamente, pero pueden reducir el impacto.</strong></p><p>El rol de las cuentas múltiples:</p><ul><li>Dispersar solicitudes, reducir la probabilidad de que una cuenta única active límites</li><li>Si una cuenta es bloqueada, otras cuentas siguen disponibles</li><li>Cambiar automáticamente cuando se encuentran límites, mejorar disponibilidad</li></ul><p><strong>Pero las cuentas múltiples no son un &quot;amuleto&quot;</strong>:</p><ul><li>Si todas las cuentas activan la detección de abuso, pueden ser bloqueadas todas</li><li>No abuses de cuentas múltiples para solicitudes intensivas</li><li>Cada cuenta aún debe seguir las mejores prácticas</li></ul><hr><h2 id="puntos-de-verificacion-✅" tabindex="-1">Puntos de Verificación ✅ <a class="header-anchor" href="#puntos-de-verificacion-✅" aria-label="Permalink to &quot;Puntos de Verificación ✅&quot;">​</a></h2><p>Después de leer esta lección, deberías saber:</p><ul><li>[ ] El uso de este plugin puede violar los TdS de Google, asumes el riesgo</li><li>[ ] Cuenta nueva + suscripción Pro/Ultra es un escenario de alto riesgo</li><li>[ ] Se recomienda usar cuentas de Google establecidas</li><li>[ ] Configurar múltiples cuentas puede dispersar el riesgo</li><li>[ ] Las cuentas bloqueadas no pueden recuperarse mediante apelación</li><li>[ ] Controlar la frecuencia de solicitudes y el uso es muy importante</li></ul><hr><h2 id="resumen-de-la-leccion" tabindex="-1">Resumen de la Lección <a class="header-anchor" href="#resumen-de-la-leccion" aria-label="Permalink to &quot;Resumen de la Lección&quot;">​</a></h2><p>Esta lección introdujo los riesgos potenciales de usar el plugin Antigravity Auth:</p><ol><li><strong>Riesgo principal</strong>: Puede violar los TdS de Google, la cuenta puede ser bloqueada o recibir shadow ban</li><li><strong>Escenarios de alto riesgo</strong>: Cuentas nuevas, cuenta nueva + suscripción, solicitudes intensivas, cuenta única crítica</li><li><strong>Mejores prácticas</strong>: Usar cuenta antigua, configurar múltiples cuentas, controlar uso, monitorear estado, &quot;calentar&quot; primero</li><li><strong>Preguntas frecuentes</strong>: No se puede apelar, el riesgo varía según la persona, múltiples cuentas pueden reducir el impacto</li></ol><p>Antes de usar este plugin, evalúa cuidadosamente los riesgos. Si no puedes aceptar las consecuencias de que la cuenta pueda ser bloqueada, se recomienda usar directamente <a href="https://idx.google.com/" target="_blank" rel="noreferrer">Antigravity IDE</a>.</p><hr><h2 id="apendice-referencia-del-codigo-fuente" tabindex="-1">Apéndice: Referencia del Código Fuente <a class="header-anchor" href="#apendice-referencia-del-codigo-fuente" aria-label="Permalink to &quot;Apéndice: Referencia del Código Fuente&quot;">​</a></h2><details><summary><strong>Haz clic para ver la ubicación del código fuente</strong></summary><blockquote><p>Última actualización: 2026-01-23</p></blockquote><p>El contenido de esta lección se basa en la sección de advertencia de riesgos del README del proyecto (README.md:23-40), no involucra implementación de código específica.</p><table tabindex="0"><thead><tr><th>Función</th><th>Ruta del archivo</th><th>Línea</th></tr></thead><tbody><tr><td>Declaración de advertencia de TdS</td><td><a href="https://github.com/NoeFabris/opencode-antigravity-auth/blob/main/README.md#L23-L40" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>23-40</td></tr></tbody></table></details>',99)])])}const g=a(t,[["render",n]]);export{m as __pageData,g as default};
